var curRx=null,rxAF=null;
function initReactions(){
  document.getElementById('rxList').innerHTML=reactions.map(function(rx,i){
    return'<div class="rx-item" id="rxi'+i+'" onclick="selectRx('+i+')">'+'<div class="rx-item-title">'+rx.title+'</div><div class="rx-item-eq">'+rx.eq+'</div>'+'<div class="rx-item-type" style="background:'+rx.color+'22;color:'+rx.color+';border:1px solid '+rx.color+'44;">'+rx.type+'</div></div>';
  }).join('');
}
initReactions();

function selectRx(i){
  var rx=reactions[i];curRx=rx;
  document.querySelectorAll('.rx-item').forEach(function(el,j){el.classList.toggle('on',j===i);});
  var main=document.getElementById('rxMain');
  main.innerHTML='<div><div style="display:flex;align-items:flex-start;justify-content:space-between;flex-wrap:wrap;gap:10px;">'+'<div><div style="font-size:20px;font-weight:800;margin-bottom:4px;">'+rx.title+'</div>'+'<div style="font-size:10px;margin-bottom:8px;"><span style="background:'+rx.color+'22;color:'+rx.color+';border:1px solid '+rx.color+'44;padding:2px 8px;border-radius:4px;">'+rx.type+'</span></div>'+'<div class="rx-eq-box">'+rx.eq+'</div></div>'+'<div style="display:flex;gap:8px;flex-wrap:wrap;">'+'<button class="voice-btn" id="rxVBtn" onclick="speakRx()">🔊 Hear Explanation</button>'+'<button class="voice-btn" style="background:var(--s2);color:var(--text);" onclick="stopSpeech()">⏹ Stop</button></div></div>'+'<canvas class="rxcv" id="rxCv"></canvas>'+'<div><div class="ict" style="margin-bottom:8px;">Step-by-Step Process</div><div class="rx-steps">'+rx.steps.map(function(s,si){return'<div class="rx-step"><div class="rx-sn">'+(si+1)+'</div><div style="font-size:12px;line-height:1.5;">'+s+'</div></div>';}).join('')+'</div></div>'+'<div><div class="ict" style="margin-bottom:8px;">📜 Voice Script</div><div style="background:rgba(99,102,241,.05);border:1px solid rgba(99,102,241,.12);border-radius:8px;padding:12px;font-size:12px;line-height:1.7;font-style:italic;">'+rx.voice+'</div></div>'+'<div><div class="ict" style="margin-bottom:8px;">📚 NCERT Notes</div><div class="ncert-note">'+rx.ncert+'</div></div></div>';
  setTimeout(function(){playRxAnim(rx);},80);
}

function speakRx(){
  if(!curRx)return;
  stopSpeech();
  var utt=new SpeechSynthesisUtterance(curRx.voice);
  function go(){var voices=window.speechSynthesis.getVoices();var mv=voices.find(function(v){return v.name.includes('Male')||v.name.includes('David')||v.name.includes('Daniel')||v.name.includes('Hemant');});if(!mv)mv=voices.find(function(v){return v.lang==='en-GB'||v.lang==='en-US';});if(mv)utt.voice=mv;utt.rate=0.88;utt.pitch=0.95;utt.volume=1;window.speechSynthesis.speak(utt);}
  if(window.speechSynthesis.getVoices().length===0){window.speechSynthesis.onvoiceschanged=go;}else{go();}
}
function stopSpeech(){if(window.speechSynthesis.speaking)window.speechSynthesis.cancel();}

function playRxAnim(rx){
  if(rxAF)cancelAnimationFrame(rxAF);
  var cv=document.getElementById('rxCv');if(!cv)return;
  cv.width=cv.offsetWidth||600;cv.height=300;
  var ctx=cv.getContext('2d');var W=cv.width,H=cv.height,cx=W/2,cy=H/2;
  var t=0;var particles=[];
  function addP(x,y,vx,vy,r,col,life){particles.push({x:x,y:y,vx:vx,vy:vy,r:r,c:col,l:life,ml:life});}
  function fr(){
    t++;ctx.fillStyle='rgba(0,12,30,.2)';ctx.fillRect(0,0,W,H);
    var type=rx.anim;
    if(type==='explosion'){
      ctx.fillStyle='rgba(0,80,180,.25)';ctx.fillRect(0,cy+20,W,H-cy-20);
      if(t%3===0)for(var pi=0;pi<3;pi++){addP(cx+(Math.random()-.5)*60,cy+15,(Math.random()-.5)*5,-Math.random()*7-1,2+Math.random()*3,'#fbbf24',60);}
      ctx.fillStyle='rgba(180,180,120,.9)';ctx.fillRect(cx-22,cy+5,44,26);
      ctx.fillStyle='#fff';ctx.font='bold 11px Space Mono';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('Na',cx,cy+18);ctx.textBaseline='alphabetic';
      if(t>18){var fl=20+Math.sin(t*.35)*12;ctx.fillStyle='rgba(255,160,0,.7)';ctx.beginPath();ctx.ellipse(cx,cy+5,15,fl,0,0,Math.PI*2);ctx.fill();}
      if(t>12){ctx.fillStyle='rgba(0,229,255,.7)';ctx.font='10px Inter';ctx.textAlign='center';ctx.fillText('H₂ ↑',cx,cy-25);}
    }else if(type==='burn'){
      if(t%2===0)for(var fi=0;fi<6;fi++){addP(cx+(Math.random()-.5)*28,cy-5,(Math.random()-.5)*4,-Math.random()*7-1,2+Math.random()*3,'#fff',55);}
      ctx.fillStyle='rgba(120,90,60,.5)';ctx.fillRect(cx-5,cy+10,10,55);
      var glow=ctx.createRadialGradient(cx,cy-5,0,cx,cy,85+Math.sin(t*.22)*20);glow.addColorStop(0,'rgba(255,255,255,.45)');glow.addColorStop(.25,'rgba(255,200,0,.2)');glow.addColorStop(1,'transparent');
      ctx.fillStyle=glow;ctx.fillRect(0,0,W,H);
    }else if(type==='neutralize'){
      var ph=Math.max(7,14-Math.min(t/280,1)*7);var hue=ph<7?0:(ph===7?120:240);
      ctx.fillStyle='hsla('+hue+',60%,45%,.3)';ctx.fillRect(cx-65,cy-45,130,90);ctx.strokeStyle='rgba(255,255,255,.15)';ctx.lineWidth=1;ctx.strokeRect(cx-65,cy-45,130,90);
      ctx.fillStyle='#fff';ctx.font='13px Inter';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('pH ≈ '+Math.round(ph),cx,cy);ctx.textBaseline='alphabetic';
      if(t%8===0)addP(cx+(Math.random()-.5)*40,cy-35,(Math.random()-.5),-Math.random()*1.5,2,'#60a5fa',50);
    }else if(type==='ionic'){
      var prog=Math.min(1,t/200);var naX=cx-90+prog*55,clX=cx+90-prog*50;
      var ng=ctx.createRadialGradient(naX,cy,0,naX,cy,26);ng.addColorStop(0,'#fff');ng.addColorStop(.4,'#fca5a5');ng.addColorStop(1,'#ef444444');
      ctx.beginPath();ctx.arc(naX,cy,26,0,Math.PI*2);ctx.fillStyle=ng;ctx.fill();
      ctx.fillStyle='#1a202c';ctx.font='bold 12px Space Mono';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText('Na',naX,cy);
      var cg=ctx.createRadialGradient(clX,cy,0,clX,cy,24);cg.addColorStop(0,'#fff');cg.addColorStop(.4,'#fde68a');cg.addColorStop(1,'#eab30844');
      ctx.beginPath();ctx.arc(clX,cy,24,0,Math.PI*2);ctx.fillStyle=cg;ctx.fill();
      ctx.fillStyle='#1a202c';ctx.fillText('Cl',clX,cy);ctx.textBaseline='alphabetic';
      if(prog>.3&&prog<.7){var ePct=(prog-.3)/.4;var ex=naX+(clX-naX)*ePct;ctx.fillStyle='#00e5ff';ctx.beginPath();ctx.arc(ex,cy-28,5,0,Math.PI*2);ctx.fill();}
      if(prog>.75){ctx.fillStyle='rgba(255,255,255,.7)';ctx.font='12px Inter';ctx.textAlign='center';ctx.fillText('Na⁺  Cl⁻  →  NaCl',cx,cy+55);}
    }else if(type==='electrolysis'){
      ctx.fillStyle='rgba(0,100,180,.25)';ctx.fillRect(cx-75,cy-35,150,80);
      ctx.fillStyle='#888';ctx.fillRect(cx-55,cy-55,7,65);ctx.fillRect(cx+48,cy-55,7,65);
      ctx.fillStyle='rgba(0,229,255,.85)';ctx.font='9px Space Mono';ctx.textAlign='center';ctx.fillText('(-) Cathode',cx-52,cy-62);
      ctx.fillStyle='rgba(249,115,22,.85)';ctx.fillText('(+) Anode',cx+52,cy-62);
      if(t%3===0){addP(cx-52,cy-35,(Math.random()-.5),-Math.random()*2,2.5,'#86efac',45);addP(cx-52,cy-35,(Math.random()-.5),-Math.random()*2,2.5,'#86efac',45);}
      if(t%5===0)addP(cx+52,cy-35,(Math.random()-.5),-Math.random()*2,2.5,'#fb923c',45);
      ctx.fillStyle='rgba(134,239,172,.8)';ctx.fillText('H₂ ↑',cx-52,cy-85);
      ctx.fillStyle='rgba(251,146,60,.8)';ctx.fillText('O₂ ↑',cx+52,cy-85);
      ctx.fillStyle='rgba(255,215,0,.75)';ctx.font='11px Inter';ctx.fillText('⚡ DC Current',cx,cy+65);
    }
    particles=particles.filter(function(p){return p.l>0;});
    particles.forEach(function(p){p.x+=p.vx;p.y+=p.vy;p.vy+=.08;p.l--;var al=Math.max(0,p.l/p.ml);ctx.beginPath();ctx.arc(p.x,p.y,Math.max(.5,p.r*al),0,Math.PI*2);ctx.fillStyle=p.c+(('0'+Math.round(al*255).toString(16)).slice(-2));ctx.fill();});
    ctx.fillStyle='rgba(255,255,255,.88)';ctx.font='bold 11px Space Mono';ctx.textAlign='center';ctx.fillText(rx.eq,W/2,16);
    rxAF=requestAnimationFrame(fr);
  }fr();
}

