var orgMolAF=null;
function showOrg(key){
  document.querySelectorAll('.org-link').forEach(function(b){b.classList.toggle('on',b.getAttribute('onclick').includes("'"+key+"'"));});
  var d=orgData[key];if(!d)return;
  var m=document.getElementById('orgMain');
  m.innerHTML='<div style="font-size:22px;font-weight:800;margin-bottom:3px;">'+d.title+'</div>'+'<div style="font-family:var(--mono);font-size:14px;color:var(--yellow);background:rgba(245,158,11,.08);padding:5px 12px;border-radius:7px;display:inline-block;margin-bottom:14px;">'+d.formula+' | '+d.hybrid+' | '+d.angle+'</div>'+'<p style="font-size:12px;color:var(--muted);margin-bottom:16px;line-height:1.6;">'+d.intro+'</p>'+'<div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:16px;">'+'<div class="icard"><div class="ict">🔬 3D Model</div><canvas class="mol3d" id="orgCv"></canvas><div style="text-align:center;margin-top:7px;"><button onclick="speakOrg(\''+key+'\')" class="voice-btn" style="display:inline-flex;font-size:11px;padding:7px 14px;">🔊 Hear Explanation</button></div></div>'+'<div class="icard"><div class="ict">📐 Properties</div><div class="pg">'+d.props.map(function(p){return'<div class="pi"><div class="pl">'+p.l+'</div><div class="pv" style="font-size:10px;">'+p.v+'</div></div>';}).join('')+'</div></div></div>'+'<div class="icard"><div class="ict">⚗ Key Reactions</div>'+d.reactions.map(function(rx){return'<div class="rxn-card"><div class="rxn-name">'+rx.name+'</div><div class="rxn-eq">'+rx.eq+'</div><div style="font-size:9.5px;color:var(--a3);margin-bottom:3px;">Conditions: '+rx.cond+'</div><div class="rxn-desc">'+rx.desc+'</div></div>';}).join('')+'</div>';
  setTimeout(function(){drawOrgMol(d.atoms);},60);
}
function drawOrgMol(atoms){
  if(orgMolAF)cancelAnimationFrame(orgMolAF);
  var cv=document.getElementById('orgCv');if(!cv||!atoms||!atoms.length)return;
  cv.width=cv.offsetWidth||280;cv.height=200;
  var ctx=cv.getContext('2d');var ang=0;
  function fr(){ang+=0.014;ctx.clearRect(0,0,cv.width,cv.height);ctx.fillStyle='rgba(0,12,30,.3)';ctx.fillRect(0,0,cv.width,cv.height);
    var cx=cv.width/2,cy=cv.height/2,sc=Math.min(cv.width,cv.height)*.38;
    for(var i=1;i<atoms.length;i++){var a0=atoms[0],ai=atoms[i];var x0=cx+(a0.x-.5)*sc*2*Math.cos(ang),y0=cy+(a0.y-.5)*sc*2;var xi=cx+(ai.x-.5)*sc*2*Math.cos(ang+.2),yi=cy+(ai.y-.5)*sc*2;var gd2=ctx.createLinearGradient(x0,y0,xi,yi);gd2.addColorStop(0,a0.c+'88');gd2.addColorStop(1,ai.c+'88');ctx.beginPath();ctx.moveTo(x0,y0);ctx.lineTo(xi,yi);ctx.strokeStyle=gd2;ctx.lineWidth=4;ctx.stroke();}
    atoms.forEach(function(a,idx){var ax=cx+(a.x-.5)*sc*2*Math.cos(ang+idx*.16);var ay=cy+(a.y-.5)*sc*2;var rv=a.r*(1+.08*Math.sin(ang+idx));ctx.beginPath();ctx.arc(ax+1.5,ay+2,rv,0,Math.PI*2);ctx.fillStyle='rgba(0,0,0,.25)';ctx.fill();var sg=ctx.createRadialGradient(ax-rv*.3,ay-rv*.3,rv*.07,ax,ay,rv);sg.addColorStop(0,'rgba(255,255,255,.6)');sg.addColorStop(.4,a.c);sg.addColorStop(1,a.c+'44');ctx.beginPath();ctx.arc(ax,ay,rv,0,Math.PI*2);ctx.fillStyle=sg;ctx.fill();ctx.strokeStyle='rgba(255,255,255,.2)';ctx.lineWidth=1;ctx.stroke();ctx.fillStyle='#fff';ctx.font='bold '+(rv>11?9:7)+'px Space Mono,monospace';ctx.textAlign='center';ctx.textBaseline='middle';ctx.fillText(a.s,ax,ay);});
    orgMolAF=requestAnimationFrame(fr);}
  fr();
}
function speakOrg(key){var d=orgData[key];if(!d)return;stopSpeech();var utt=new SpeechSynthesisUtterance(d.voice);function go(){var v=window.speechSynthesis.getVoices();var mv=v.find(function(x){return x.name.includes('David')||x.name.includes('Daniel')||x.name.includes('Male');});if(!mv)mv=v.find(function(x){return x.lang==='en-GB'||x.lang==='en-US';});if(mv)utt.voice=mv;utt.rate=0.88;utt.pitch=0.95;window.speechSynthesis.speak(utt);}if(window.speechSynthesis.getVoices().length===0){window.speechSynthesis.onvoiceschanged=go;}else{go();}}

